func consume(session sarama.ConsumerGroupSession, msg *sarama.ConsumerMessage) {
    if err := processMessage(msg); err != nil {
        log.Error("failed to process", "err", err, "offset", msg.Offset)
        // No commit → message redelivered → infinite retry loop
        // All messages behind this one in the partition are blocked
    }
    session.MarkMessage(msg, "")
}
